        }

        /* Status/Info */
        #status {
            margin-top: 20px;
            font-size: 1.1em;
            min-height: 20px;
        }
    </style>
</head>
<body>

    <h1>Falling Sand Sandbox</h1>

    <div id="controls">
        <div class="material-selector" id="material-buttons">
            <!-- Buttons populated by JS -->
        </div>
        <button id="clear">Clear Grid</button>
    </div>

    <canvas id="sand"></canvas>
    <div id="status">Ready. Painting material: Sand</div>

    <script>
        // --- CONFIGURATION AND INITIALIZATION ---
        const CANVAS_SIZE = 400; // CSS pixels
        const GRID_W = 80;       // Cells wide
        const GRID_H = 80;       // Cells high (y=0 is top)

        const MATERIALS = {
            EMPTY: "empty",
            SAND: "sand",
            WATER: "water",
            WALL: "wall",
            ACID: "acid"
        };

        let currentMaterial = MATERIALS.SAND;
        let canvas, ctx;
        let grid = []; // The 2D array representing the simulation state

        // --- CORE SIMULATION LOGIC (The Grid State) ---

        /**
         * Initializes the internal grid structure.
         */
        function initializeGrid() {
            grid = Array(GRID_H).fill(0).map(() => Array(GRID_W).fill(MATERIALS.EMPTY));
        }

        /**
         * Gets the material at (x, y) safely. Handles boundaries by returning EMPTY.
         */
        function getMaterial(x, y) {
            if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) {
                return MATERIALS.EMPTY; // Treat outside bounds as empty space
            }
            return grid[y][x];
        }

        /**
         * Sets the material at (x, y). Checks boundaries first.
         */
        function setMaterial(x, y, material) {
            if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                grid[y][x] = material;
                return true;
            }
            return false;
        }

        // --- SIMULATION API IMPLEMENTATION ---

        const sim = {
            w: GRID_W,
            h: GRID_H,

            /**
             * Processes movement for all particles bottom-up.
             * @param {number} n - Number of steps to simulate (must be 1 for standard tick).
             */
            tick(n) {
                for (let step = 0; step < n; step++) {
                    // Process from the second row up to the top, ensuring bottom-up movement.
                    // We iterate y=H-2 down to y=0 because particles fall/move downwards (increasing y index).
                    for (let y = GRID_H - 2; y >= 0; y--) {
                        for (let x = 0; x < GRID_W; x++) {
                            const material = getMaterial(x, y);

                            if (material === MATERIALS.EMPTY || material === MATERIALS.WALL) {
                                continue; // Walls don't move, empty space does nothing.
                            }

                            // Check if the particle needs to move/react
                            let moved = false;

                            switch (material) {
                                case MATERIALS.SAND:
                                    moved = handleSand(x, y);
                                    break;
                                case MATERIALS.WATER:
                                    moved = handleWater(x, y);
                                    break;
                                case MATERIALS.ACID:
                                    moved = handleAcid(x, y);
                                    break;
                            }

                            // If the particle moved or reacted, we assume its state is updated for the next cell check.
                        }
                    }
                }
            },

            get(x, y) {
                return getMaterial(Math.floor(x), Math.floor(y));
            },

            set(x, y, material) {
                return setMaterial(Math.floor(x), Math.floor(y), material);
            },

            clear() {
                initializeGrid();
                drawGrid();
            }
        };


        // --- MOVEMENT HANDLERS (Physics Rules) ---

        /**
         * Sand falls straight down, or slides diagonally if blocked.
         */
        function handleSand(x, y) {
            const nextY = y + 1;
            let targetMaterial = getMaterial(x, nextY);

            // 1. Fall Straight Down (Priority 1)
            if (targetMaterial === MATERIALS.EMPTY) {
                setMaterial(x, y, MATERIALS.EMPTY);
                setMaterial(x, nextY, MATERIALS.SAND);
                return true;
            }

            // 2. Slide Diagonally (If blocked below)
            const dx = Math.floor(Math.random() * 3) - 1; // -1, 0, 1
            let newX = x + dx;
            let newY = y + 1;

            // Check if the diagonal spot is empty and within bounds
            if (newX >= 0 && newX < GRID_W && getMaterial(newX, newY) === MATERIALS.EMPTY) {
                setMaterial(x, y, MATERIALS.EMPTY);
                setMaterial(newX, newY, MATERIALS.SAND);
                return true;
            }

            // If all else fails, it rests (no change).
            return false;
        }


        /**
         * Water falls like sand. If blocked, spreads horizontally into empty cells.
         */
        function handleWater(x, y) {
            const nextY = y + 1;
            let targetMaterial = getMaterial(x, nextY);

            // 1. Fall Straight Down (Priority 1)
            if (targetMaterial === MATERIALS.EMPTY) {
                setMaterial(x, y, MATERIALS.EMPTY);
                setMaterial(x, nextY, MATERIALS.WATER);
                return true;
            }

            // 2. Spread Horizontally (If blocked below)
            const neighbors = [];
            if (x > 0 && getMaterial(x - 1, y) === MATERIALS.EMPTY) {
                neighbors.push(x - 1);
            }
            if (x < GRID_W - 1 && getMaterial(x + 1, y) === MATERIALS.EMPTY) {
                neighbors.push(x + 1);
            }

            if (neighbors.length > 0) {
                const targetX = neighbors[Math.floor(Math.random() * neighbors.length)];

                // Move water to the empty neighbor spot
                setMaterial(x, y, MATERIALS.EMPTY);
                setMaterial(targetX, y, MATERIALS.WATER);
                return true;
            }

            return false; // Rests
        }


        /**
         * Acid moves like water, and dissolves sand/wall cells it touches below or beside.
         */
        function handleAcid(x, y) {
            const nextY = y + 1;
            let targetMaterial = getMaterial(x, nextY);

            // --- Phase 1: Movement (Like Water) ---
            let moved = false;

            if (targetMaterial === MATERIALS.EMPTY) {
                // Fall straight down
                setMaterial(x, y, MATERIALS.EMPTY);
                setMaterial(x, nextY, MATERIALS.ACID);
                moved = true;
            } else if (targetMaterial !== MATERIALS.WATER && targetMaterial !== MATERIALS.ACID) {
                // Try horizontal spread (if blocked below by non-liquid/non-acid material)
                const neighbors = [];
                if (x > 0 && getMaterial(x - 1, y) === MATERIALS.EMPTY) {
                    neighbors.push(x - 1);
                }
                if (x < GRID_W - 1 && getMaterial(x + 1, y) === MATERIALS.EMPTY) {
                    neighbors.push(x + 1);
                }

                if (neighbors.length > 0) {
                    const targetX = neighbors[Math.floor(Math.random() * neighbors.length)];
                    setMaterial(x, y, MATERIALS.EMPTY);
                    setMaterial(targetX, y, MATERIALS.ACID);
                    moved = true;
                }
            }

            // --- Phase 2: Dissolution (Always check surroundings) ---
            if (!moved) { // Only dissolve if we didn't move away from the spot
                 const neighborsToCheck = [
                    {x: x, y: y + 1}, // Below
                    {x: x - 1, y: y}, // Left
                    {x: x + 1, y: y}  // Right
                ];

                for (const {x: nx, y: ny} of neighborsToCheck) {
                    if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H) {
                        const target = getMaterial(nx, ny);
                        if ((target === MATERIALS.SAND || target === MATERIALS.WALL)) {
                            // Dissolve the target material and potentially move acid into its spot if it was blocking movement
                            setMaterial(nx, ny, MATERIALS.EMPTY);

                            // If we dissolved something directly below us (y+1), we might need to fall/spread now.
                            if (ny === y + 1 && getMaterial(x, y) !== MATERIALS.ACID) {
                                // Re-triggering movement check is complex in a single pass. For simplicity and stability,
                                // if dissolution happens, the acid simply occupies the space where the material was removed.
                            }

                            // If we dissolved something beside us, it just disappears.
                        }
                    }
                }
            }


            return moved;
        }


        // --- RENDERING AND UI HANDLING ---

        /**
         * Maps a material name to its color and draws the entire grid state.
         */
        function drawGrid() {
            const pixelSize = CANVAS_SIZE / GRID_W;
            ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];
                    ctx.fillStyle = getMaterialColor(material);
                    ctx.fillRect(x * pixelSize, y * pixelSize, pixelSize, pixelSize);
                }
            }
        }

        /**
         * Determines the CSS color for a given material.
         */
        function getMaterialColor(material) {
            switch (material) {
                case MATERIALS.EMPTY: return 'rgb(51, 51, 51)'; // Dark grey background
                case MATERIALS.SAND: return '#ffc107';
                case MATERIALS.WATER: return '#29b6f6';
                case MATERIALS.WALL: return '#607d8b';
                case MATERIALS.ACID: return '#ff9800';
                default: return 'black';
            }
        }

        /**
         * Handles mouse painting interaction on the canvas.
         */
        function handlePainting(e) {
            const rect = canvas.getBoundingClientRect();
            const xPixel = e.clientX - rect.left;
            const yPixel = e.clientY - rect.top;

            // Calculate grid coordinates (0 to GRID_W-1, 0 to GRID_H-1)
            const x = Math.floor((xPixel / CANVAS_SIZE) * GRID_W);
            const y = Math.floor((yPixel / CANVAS_SIZE) * GRID_H);

            // Set the material if it's currently empty or different from selected
            if (getMaterial(x, y) !== currentMaterial && getMaterial(x, y) !== MATERIALS.EMPTY) {
                sim.set(x, y, currentMaterial);
                drawGrid();
            }
        }

        // --- SETUP AND EVENT LISTENERS ---

        function setupUI() {
            const materialNames = [
                { id: 'mat-sand', name: MATERIALS.SAND },
                { id: 'mat-water', name: MATERIALS.WATER },
                { id: 'mat-wall', name: MATERIALS.WALL },
                { id: 'mat-acid', name: MATERIALS.ACID },
                { id: 'mat-empty', name: MATERIALS.EMPTY }
            ];

            const buttonContainer = document.getElementById('material-buttons');
            buttonContainer.innerHTML = ''; // Clear existing content

            materialNames.forEach(m => {
                const btn = document.createElement('button');
                btn.className = 'material-button material-selector';
                btn.id = m.id;
                btn.textContent = m.name.toUpperCase();
                btn.dataset.material = m.name;

                if (m.name === MATERIALS.SAND) {
                    btn.classList.add('selected');
                    currentMaterial = m.name;
                }

                btn.addEventListener('click', () => {
                    // Update selection state
                    document.querySelectorAll('.material-button').forEach(b => b.classList.remove('selected'));
                    btn.classList.add('selected');
                    currentMaterial = btn.dataset.material;
                    document.getElementById('status').textContent = `Painting material: ${currentMaterial.toUpperCase()}`;
                });

                buttonContainer.appendChild(btn);
            });

            // Clear Button Listener
            document.getElementById('clear').addEventListener('click', () => {
                if (confirm("Are you sure you want to clear the entire grid?")) {
                    sim.clear();
                }
            });

            // Canvas Painting Listeners
            canvas.addEventListener('mousedown', (e) => {
                handlePainting(e);
                isDrawing = true;
            });
            canvas.addEventListener('mousemove', (e) => {
                if (isDrawing) handlePainting(e);
            });
            document.addEventListener('mouseup', () => {
                isDrawing = false;
            });

        }

        // --- GAME LOOP AND INITIALIZATION ---

        let isDrawing = false;

        function gameLoop() {
            // Run the simulation one step synchronously
            sim.tick(1);
            drawGrid();
            requestAnimationFrame(gameLoop);
        }


        window.onload = () => {
            canvas = document.getElementById('sand');
            ctx = canvas.getContext('2d');

            // Set CSS dimensions (must be at least 400x400)
            canvas.style.width = `${CANVAS_SIZE}px`;
            canvas.style.height = `${CANVAS_SIZE}px`;
            canvas.width = CANVAS_SIZE; // Internal resolution for drawing consistency
            canvas.height = CANVAS_SIZE;

            initializeGrid();
            setupUI();
            drawGrid();

            // Start the animation loop
            gameLoop();
        };

    </script>
</body>
</html>
